INSERT INTO public.blogs (title, slug, excerpt, content, image_url, author, category, read_time) VALUES
(
  'Advanced TIG Welding: Mastering Exotic Alloys',
  'advanced-tig-welding-exotic-alloys',
  'A deep dive into Tungsten Inert Gas (TIG) welding techniques required for high-stress aerospace and petrochemical applications.',
  '<h1>The Art of the Arc</h1><p>Welding is often seen as brute force joining, but when dealing with exotic alloys like Inconel, Monel, or Titanium, it becomes a high-precision science. Tungsten Inert Gas (TIG) welding, or GTAW, is the only process that offers the granular control necessary to prevent micro-cracking and metallurgical degradation in these sensitive materials.</p><h2>Controlling the Heat Input</h2><p>The primary challenge with exotic alloys is managing heat input. Titanium, for example, is highly reactive at elevated temperatures and will absorb oxygen, nitrogen, and hydrogen from the atmosphere if not perfectly shielded. This leads to embrittlement. Our specialized trailing shield setups ensure an argon blanket covers the weld pool until it drops below 400°C.</p><p>By investing in pulse-TIG power sources, our fabricators can manipulate the arc waveform, depositing filler metal at lower average amperages. This minimizes the heat-affected zone (HAZ) and preserves the material''s inherent corrosion resistance.</p>',
  '/assets/slides/slide-4.webp',
  'Ahmed Hassan',
  'Technical Insights',
  '5 min read'
),
(
  'Navigating Steel Supply Chains in the Middle East',
  'navigating-steel-supply-chains-mena',
  'Strategies for mitigating volatility in global steel prices and ensuring reliable material delivery for mega-projects in the GCC.',
  '<h1>Volatility as the New Normal</h1><p>The global steel supply chain is subject to geopolitical shifts, energy crises, and volatile shipping rates. For contractors in the Middle East executing mega-projects, waiting 6 months for a shipment of H-beams from Asia is no longer tenable.</p><h2>Strategic Stockpiling and Near-Shoring</h2><p>At Jazeerat Al Hadeed, we have adapted by shifting from Just-In-Time (JIT) manufacturing to a hybrid model that includes strategic stockpiling of high-demand sections (like UB, UC, and heavy plates). Furthermore, we are increasingly relying on regional mills in the UAE and Saudi Arabia to near-shore our supply.</p><p>This insulation against global shocks allows us to lock in prices for our clients during the tender phase and guarantee fabrication schedules, which is the ultimate currency in construction.</p>',
  '/assets/slides/slide-5.webp',
  'Sarah Jenkins',
  'Industry News',
  '4 min read'
),
(
  'The Role of Digital Marketing in Construction',
  'digital-marketing-in-construction-b2b',
  'Why heavy industry and construction firms must adopt digital marketing and SEO to secure high-value B2B contracts in the modern era.',
  '<h1>Moving Beyond Word of Mouth</h1><p>For decades, the construction and structural steel industries relied almost exclusively on networking, tenders, and word-of-mouth. While relationships still matter, the procurement process has fundamentally changed. Today, when an international EPC contractor needs a local fabrication partner in the UAE, their first step is a Google search.</p><h2>Local SEO and Technical Authority</h2><p>This is where Digital Marketing becomes a revenue driver, not just a brochure. By optimizing our website for local SEO—claiming our Google Business Profile, building backlinks in UAE directories, and producing highly technical content (like this blog!)—we signal our authority to search engines and procurement managers alike.</p><p>A strong digital presence proves that a company is modern, transparent, and capable. It is no longer optional; it is the baseline for securing tier-one contracts.</p>',
  '/assets/slides/slide-6.webp',
  'Marcus Chen',
  'Company Updates',
  '6 min read'
),
(
  'Understanding Structural Steel Tolerances',
  'understanding-structural-steel-tolerances',
  'A technical breakdown of fabrication tolerances according to AISC standards and how they impact site erection.',
  '<h1>Millimeters Matter</h1><p>When engineering a skyscraper, the steel frame is only as good as its connections. The American Institute of Steel Construction (AISC) provides stringent guidelines for acceptable fabrication tolerances, but aiming merely for "acceptable" often leads to site delays.</p><h2>Camber, Sweep, and Length</h2><p>Three critical dimensions define a beam''s accuracy: Camber (the vertical curve), Sweep (the horizontal curve), and overall length. A variance of just 5mm in length on a major transfer girder can force the erection team to spend hours reaming holes or welding shims 30 stories in the air.</p><p>By utilizing 3D laser scanning during the QA/QC process, we can virtually assemble complex nodes before they ever leave the shop floor, ensuring absolute compliance with AISC Code of Standard Practice.</p>',
  '/assets/slides/slide-1.webp',
  'Khalid Ibrahim',
  'Technical Insights',
  '5 min read'
),
(
  'Safety First: Our New HSE Training Initiative',
  'safety-first-hse-training-initiative',
  'Announcing our comprehensive new Health, Safety, and Environment training program for all workshop and site personnel.',
  '<h1>Commitment to Zero Harm</h1><p>In heavy fabrication, the risks are inherent. Moving 10-ton steel beams, operating high-voltage welding equipment, and working at heights are daily realities. That is why Jazeerat Al Hadeed is proud to launch our "Zero Harm" HSE initiative.</p><h2>Beyond Compliance</h2><p>This program goes beyond standard regulatory compliance. It involves weekly toolbox talks, mandatory OSHA 30-hour certification for all foremen, and the implementation of wearable tech that alerts workers if they enter the swing radius of an active crane.</p><p>Safety is not a metric; it is a culture. By empowering every single worker with the authority to stop work if they see a hazard, we protect our most valuable asset: our people.</p>',
  '/assets/project-4.jpg',
  'James Okafor',
  'Company Updates',
  '3 min read'
),
(
  'The Rise of Green Steel in the Middle East',
  'rise-of-green-steel-middle-east',
  'How the MENA region is positioning itself as a global hub for low-carbon steel production using green hydrogen.',
  '<h1>Decarbonizing Heavy Industry</h1><p>Steel production accounts for roughly 7% of global greenhouse gas emissions. As the world pushes towards Net Zero, the industry is under immense pressure to decarbonize. Interestingly, the Middle East is perfectly positioned to lead this transition.</p><h2>The Hydrogen Advantage</h2><p>Traditional blast furnaces use coking coal as a reducing agent. The future is Direct Reduced Iron (DRI) powered by green hydrogen. With abundant solar energy, the GCC can produce green hydrogen cheaper than almost anywhere else on Earth.</p><p>We are actively partnering with regional mills to source lower-carbon steel for our clients, helping them achieve their LEED certification goals and reducing the embodied carbon of their structures.</p>',
  '/assets/project-5.jpg',
  'Sarah Jenkins',
  'Industry News',
  '4 min read'
),
(
  'Case Study: Erection of the Dubai Sky Bridge',
  'case-study-erection-dubai-sky-bridge',
  'An inside look at the logistical and engineering challenges of hoisting a 400-ton steel bridge between two active towers.',
  '<h1>A High-Wire Act</h1><p>Connecting two skyscrapers with a steel bridge 150 meters in the air requires extraordinary precision. For the Dubai Sky Bridge project, Jazeerat Al Hadeed was contracted to fabricate and erect the 400-ton central span.</p><h2>The Strand Jack Solution</h2><p>Traditional tower cranes maxed out at 50 tons at that radius. Instead, we engineered a custom lifting gantry on the roofs of both towers and utilized heavy-duty strand jacks. The entire 400-ton structure was fabricated in three massive modules, driven to the site at 2 AM, bolted together on the ground, and hoisted into position at a rate of 10 meters per hour.</p><p>The successful execution of this lift, with zero safety incidents and millimeter-perfect alignment, stands as one of our proudest engineering achievements.</p>',
  '/assets/project-6.jpg',
  'Ahmed Hassan',
  'Technical Insights',
  '7 min read'
),
(
  'Why We Use Tekla Structures for 3D Detailing',
  'why-we-use-tekla-structures-3d-detailing',
  'How Building Information Modeling (BIM) software eliminates clashes and streamlines the fabrication process.',
  '<h1>The Digital Twin</h1><p>Before a single piece of steel is cut, the entire project is built virtually. We utilize Tekla Structures to create highly detailed 3D Building Information Models (BIM) of every structure we fabricate.</p><h2>Clash Detection and CNC Integration</h2><p>The primary benefit of BIM is clash detection. By integrating our structural model with the MEP (Mechanical, Electrical, and Plumbing) models, we can identify intersecting pipes and beams in the software, rather than discovering them on site.</p><p>Furthermore, Tekla exports NC (Numerically Controlled) files directly to our plasma cutters and drill lines, eliminating human error in the translation from drawing to machine.</p>',
  '/assets/slides/slide-2.webp',
  'Marcus Chen',
  'Technical Insights',
  '4 min read'
),
(
  'Jazeerat Al Hadeed Achieves ISO 9001 Certification',
  'jazeerat-achieves-iso-9001-certification',
  'Celebrating our official certification for Quality Management Systems, cementing our commitment to continuous improvement.',
  '<h1>A Milestone in Quality</h1><p>We are thrilled to announce that Jazeerat Al Hadeed has officially achieved ISO 9001:2015 certification. This internationally recognized standard ensures that our products and services meet the needs of clients through an effective quality management system.</p><h2>What This Means for Our Clients</h2><p>This certification is not just a plaque on the wall. It represents a rigorous, third-party audit of our entire operation—from procurement and material traceability to fabrication, welding, and final inspection.</p><p>For our clients, it provides absolute assurance that every piece of steel leaving our facility has been subjected to a documented, standardized, and continuously improving quality process.</p>',
  '/assets/slides/slide-3.webp',
  'James Okafor',
  'Company Updates',
  '3 min read'
